"""
watch.py

Automated watcher script for WhatsApp Offers folder.
Detects new/updated offer folders, extracts chat context, and triggers offer generation.
"""
import os
import time
from pathlib import Path
from datetime import datetime
# from offer_generator import main as generate_offer

WATCH_DIR = "/Users/alaaatia/Library/Mobile Documents/com~apple~CloudDocs/WhatsApp 1447-CARSHUNTER-Rag2926/Offers/"
POLL_INTERVAL = 10  # seconds
REQUIRED_FILES = ["readme.txt"]  # Add more if needed

# Track processed folders to avoid duplicate offers
processed = set()

def folder_ready(folder):
    # Check if all required files exist in the folder
    return all((folder / req).exists() for req in REQUIRED_FILES)

def parse_contact(folder):
    # Example: folder name is contact number or name
    return folder.name

def create_card_context_folder(contact):
    today = datetime.now().strftime("%Y-%m-%d")
    card_folder = Path(WATCH_DIR) / f"CARD_{contact}_{today}_contexts"
    card_folder.mkdir(exist_ok=True)
    return card_folder

def scan_and_generate():
    for folder in Path(WATCH_DIR).iterdir():
        if folder.is_dir() and folder not in processed:
            if folder_ready(folder):
                contact = parse_contact(folder)
                card_folder = create_card_context_folder(contact)
                chat_text = (folder / "readme.txt").read_text(encoding="utf-8")
                # Trigger context operation: save chat, generate offer/invoice, etc.
                context_file = card_folder / "context.txt"
                context_file.write_text(chat_text, encoding="utf-8")
                # Uncomment below to trigger offer generation if offer_generator is available
                # generate_offer(chat_text, str(card_folder))
                processed.add(folder)
                print(f"Context and card folder generated for: {contact} on {card_folder}")

def main():
    print(f"Watching {WATCH_DIR} for new offers...")
    while True:
        scan_and_generate()
        time.sleep(POLL_INTERVAL)

if __name__ == "__main__":
    main()
